-#define ROUND_UP(x, y) ((((x) + ((y) - 1)) / (y)) * (y))
-static int ROUND_UP_BITS(uint32_t x, uint32_t y)
-{
-    // Round x up so that it has at most y bits of mantissa.
-    if (x < (1u << y))
-        return x;
-    uint32_t m = 0;
-    while (x & ~m)
-        m = (m << 1) | 1u;
-    m >>= y;
-    if (!(x & m))
-        return x;
-    return (x | m) + 1u;
-}
